          "body": {
            "version": 1,
            "nodes": [
              {
                "type": "paragraph",
                "text": "Before purchasing vending machines, operators should validate location demand. This critical step helps ensure your business has a strong foundation for success."
              },
              {
                "type": "paragraph",
                "text": "Key indicators for strong demand include:"
              },
              {
                "type": "list",
                "style": "bullet",
                "items": [
                  "High foot traffic",
                  "Significant dwell time",
                  "Limited existing food or beverage options"
                ]
              },
              {
                "type": "paragraph",
                "text": "By carefully assessing these factors, you can make informed decisions and avoid unnecessary investment in unproven locations."
              }
            ]
          }
        }
